{{Object | Name=Peugeot 106 MAXI | Guid=3055-7489 | Deck=The Peugeot 106 Maxi is a Kit-Car built by Peugeot, and is based on the road-going 106. The 106 Maxi introduced in 1996 would undergo modifications in 1997. | Characters= | Concepts=Concepts/Licensed_Cars,Concepts/Peugeot,Concepts/Rally | Franchises= | Games=Games/Gran_Turismo_2,Games/International_Rally_Championship,Games/Mobil_1_British_Rally_Championship,Games/Need_for_Speed_V_Rally,Games/Need_for_Speed_V_Rally_2,Games/Pro_Rally,Games/Pro_Rally_2001,Games/Rally_Championship_Xtreme,Games/Sebastien_Loeb_Rally_Evo,Games/Sega_Rally_Championship | Locations=Locations/France | People= | Objects=Objects/Peugeot_106,Objects/Peugeot_206_WRC,Objects/Peugeot_306_MAXI | Image=https://www.giantbomb.com/a/uploads/scale_super/151/1511438/3645530-4787799278-964.j.jpg }}
